import React, { useState } from 'react';
import { Button, Select, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatQty, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, monthStartEnd, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { DefectiveSummaryRow } from '../../../services/analytics/models';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
const BaoCaoSpLoiPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [rows, setRows] = useState<DefectiveSummaryRow[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ analyticsService.getDefectiveSummary({ fromDate, toDate }).then(d=>{if(!c)setRows(d);}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [fromDate,toDate,dispatch, reloadKey]);
  const refresh = () => setReloadKey(k => k + 1);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-exclamation-triangle" /> Sản phẩm lỗi</h1></div>
        <div className={styles.headerActions}><Button variant="secondary" onClick={()=>exportExcel('/wms/reports/defective-summary/export-excel',{fromDate,toDate},`SPLoi-${fromDate}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.filtersBar} data-testid={`erp-bao-cao-sp-loi-filters`}><DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v:DateRangeValue)=>{setFromDate(v.fromDate??'');setToDate(v.toDate??'');}} /><ListSearchRefreshButtons testIdPrefix="erp-bao-cao-sp-loi" onSearch={handleSearch} onRefresh={refresh} showSearch={false} /></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr><th>Mã</th><th>Tên</th><th className={styles.colRight}>SL</th><th>Loại lỗi</th><th>Kho</th></tr></thead><tbody>{rows.map((r,i)=>(<tr key={i}><td>{r.productCode}</td><td>{r.productName}</td><td className={styles.colRight}>{formatNumber(r.quantity)}</td><td>{r.defectType??'—'}</td><td>{r.warehouseName??'—'}</td></tr>))}</tbody></table></div>}</div>
    </div>
  );
};
export default BaoCaoSpLoiPage;
